var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"18:10 ARC-KP1\\n어느 사무실\\n<color=#ff3636>두 번째 사건 발생</color> 1시간 경과","JPN":"18:10 ARC-KP1\\nとある事務所\\n<color=#ff3636>二度目の事件発生から</color>1時間経過","ENG":"18:10 ARC-KP1\\nUnknown Office\\n1 hour after <color=#ff3636>2nd Incident</color>","TWN":"18:10 ARC-KP1\\n某間辦公室\\n<color=#ff3636>第二起事件發生</color>經過1小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"메카닉스 대표, 그 돼지 자식을 해치웠다고 보고 받았어요.","JPN":"メカニックス代表、あのブタ野郎を始末したと報告を受けました。","ENG":"I’ve just received word that the pig, the CEO of Mechanics, has been dealt with.","TWN":"我收到消息，說已經把機械代表那個豬八戒處理掉了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"이야~ 고모가 선물해 준 그거 일 처리 확실하던데요.","JPN":"いやー、叔母さんが贈ってくれたアレ、有能でしたよ。","ENG":"That thing you gave me sure did the trick.","TWN":"哇～姑姑送我的那個禮物，做事情很俐落呢！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"추가로 발주할 생각은 없어요? 돈은 고모 원하는 대로 꽂아 드릴 테니까.","JPN":"追加で発注するのはどうですか？　金なら叔母さんが欲しいだけ渡しますよ。","ENG":"Any plans to make more of them? I’ll pay however much you want, Auntie.","TWN":"姑姑不打算再多做幾個嗎？錢的事不用擔心，姑姑想要多少，我都會給姑姑弄來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"흐음, 우리 조카님 부탁인데 못 해 줄 것도 없지.","JPN":"まあ、うちの甥っ子の頼みなら聞いてあげないとね。","ENG":"Hmm, well I can’t decline my nephew’s request, can I?","TWN":"呵呵，姪子的要求，姑姑怎麼能拒絕呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AUNT_NPC_ALPHA_NULL","text":{"KOREA":"이 고모가 시키는 대로만 잘 하면 말이야.","JPN":"もちろん、この叔母さんの言うとおりにしてくれたら、だけど。","ENG":"As long as you do as you’re told.","TWN":"但前提是你要乖乖聽姑姑的話。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"걱정하지 마요, 고모. 다음 타겟도 깔끔하게 처리할 테니까.","JPN":"心配しないでください、叔母さん。\\n次のターゲットも手っ取り早く処理しますから。","ENG":"No need to be concerned, Auntie. The next target will also be a clean hit.","TWN":"姑姑請放心，下一個目標也會處理乾淨的！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"<color=#ffd34c>그것</color>만 있으면……. 식은 죽 먹기죠.","JPN":"<color=#ffd34c>アレ</color>さえあれば……朝飯前ですよ。","ENG":"It’s a piece of cake... if we have that <color=#ffd34c>thing</color>.","TWN":"只要有<color=#ffd34c>那個</color>……根本是輕而易舉！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"19:22 ARC-KP1\\n알파트릭스 본사 회의실\\n<color=#ff3636>두 번째 사건 발생</color> 2시간 경과","JPN":"19:22 ARC-KP1\\nアルファトリックス本社会議室\\n<color=#ff3636>二度目の事件発生から</color>2時間経過","ENG":"19:22 ARC-KP1\\nAlphatrix HQ Meeting Room\\n2 hours after <color=#ff3636>2nd Incident</color>","TWN":"19:22 ARC-KP1\\n阿爾法崔克斯總公司會議室\\n<color=#ff3636>第二波事件發生</color>後經過2小時"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"부회장이 살해당하고 채 하루도 지나지 않았습니다!","JPN":"副会長が殺害されてから一日も経っていません！","ENG":"Not even a day has passed since the assassination of the Vice Chairman!","TWN":"副會長遭人殺害都還不到一天！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"그런데 이번엔 메카닉스 대표라니요? 이게 말이나 됩니까?","JPN":"なのに今度はメカニックス代表ですと？　あり得ない！","ENG":"But now, even the CEO of Mechanics? This is preposterous!","TWN":"這次是機械代表遇害？這是怎麼搞的？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"여기 계신 분들의 도움으로 부회장 건이 외부에 알려지는 것은 잠시 막았습니다만…….","JPN":"ここにいらっしゃる皆様の協力のもと、\\n副会長の件が外部に知られることはしばらく防げましたが……","ENG":"We were able to keep the media quiet about our Vice Chairman’s death...","TWN":"副會長的事，是靠在座大家的幫忙，好不容易才壓下來，沒有讓消息走漏出去……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"메카닉스 대표까지 그렇게 된 이상 사건을 감추는 데에도 한계가 있어요.","JPN":"メカニックス代表までああなった以上、事件を隠すにも限界があります。","ENG":"However, with the CEO of Mechanics also being found dead, it's only a matter of time before this becomes public.","TWN":"現在連機械代表都發生這種事，要封鎖消息恐怕會有困難。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"위기대응 부서를 설득해서라도 어서 신지아를 잡아야 합니다.","JPN":"危機管理部を説得してでも、一刻も早くヒメノ・ユイを\\n捕まえなければなりません。","ENG":"We need to get the Crisis Response Department to capture Shin Jia, ASAP.","TWN":"就算要說服危機處理小組，也必須盡快抓到沈佳。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"이 사건이 알려지면 주가 폭락은 둘째 쳐도, 회장 선임에도 악영향이 갈 수 있어요.","JPN":"この事件が知られれば、株価暴落はもちろん、会長選任にも\\n悪影響を与えるでしょう。","ENG":"If word gets out, not only will the stock prices plummet, it will also negatively impact the appointment of our new President.","TWN":"這件事要是曝光，不要說股價會暴跌，更重要的是，對於選出新任會長會有不好的影響。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……그래. 주가 때문에 감찰과만 움직였던 거군.","JPN":"……なるほど。株価のために監察課だけを動かしていたのね。","ENG":"Hmm... They only put Investigations on the case because of stock prices.","TWN":"……也是，只有關係到股價時，才會出動監察科。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그리고 그 사이에 이사진들은 본인들 입맛에 맞는 차기 회장을 선발하려고 했고.","JPN":"そしてその隙に、理事会は本人たちの都合にあう次期会長を選任しようとした。","ENG":"And meanwhile, they were going to appoint a new President they saw fit.","TWN":"而且這種時候，董事會還是只想到要選出他們想要的會長。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그러고 보면, 그 때 부회장님도…….","JPN":"そういえば、あの時副会長も……","ENG":"Come to think of it, the Vice Chairman also said something that night...","TWN":"這麼說來，那時候副會長也……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이사회는 신씨 집안과 관계없이 그룹의 장기 침체를 타파할 수 있는 인물에 주목할 겁니다.","JPN":"理事会はヒメノ家とは関係が無く、\\nグループの長期低迷を打破できる人物に注目すると思います。","ENG":"Regardless of any connections any candidate has with the Shin family, the board will choose someone who can lead the Group out of its long slump.","TWN":"董事會應該會推選跟沈家沒關係，而且能夠打破集團長期窘境的人。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"넉넉잡아 두셋 정도를 꼽을 수 있겠죠.","JPN":"多めに見積もっても2人、3人くらいに絞られるでしょう。","ENG":"I believe there are two to three potential candidates.","TWN":"符合條件的人應該有2、3位。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"그야 그렇겠지. 그것들은 우리 집안에 형님 말고는 인물이 없다고 떠들어댔으니 말이야.","JPN":"まあ、そうだろうな。我が一族には兄以外に人材がいないと騒いでいたからな。","ENG":"Ah, yes. They were always saying how my big brother was best fit to run the company.","TWN":"我想也是，那些傢伙認為我們沈家除了大哥之外，都沒有其他人才。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"예를 들면?","JPN":"例えば、どのあたりだ？","ENG":"Any names?","TWN":"那你說說看有誰？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"우선, <color=#ffd34c>일렉트로닉스</color> 대표가 유력하겠죠. 전자제품 분야는 실적 부진을 극복한 이력이 있으니 말입니다.","JPN":"まず、<color=#ffd34c>エレクトロニクス</color>の代表が有力でしょう。\\n電子製品分野は業績不振を打開した実績がありますので。","ENG":"To begin with, the CEO of <color=#ffd34c>Electronics</color> is one. Because that person has a track record of overcoming sluggish performance in our electronics sector.","TWN":"首先最有力的人選應該是<color=#ffd34c>電子</color>的代表。畢竟他有過讓電子產品業績起死回生的經驗。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"괜찮은 친구긴 한데 사람이 너무 경박해. 계열사 수장 정도가 적당하지.","JPN":"悪くはないが、薄っぺらい人物だ。系列会社の社長くらいがピッタリだろう。","ENG":"I guess so. But that fellow’s too carefree. More suited as a head of one of the divisions, in my opinion.","TWN":"他是還不錯，但太個性輕浮，充其量只能當個分公司的總經理吧！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"사교성은 부족하지만 <color=#ffd34c>메카닉스</color> 대표는 어떻겠나?","JPN":"社交性は足りないが、<color=#ffd34c>メカニックス</color>の代表はどうだ？","ENG":"Although he lacks some social skills, what about the CEO of <color=#ffd34c>Mechanics</color>?","TWN":"那你覺得<color=#ffd34c>機械</color>的代表怎麼樣？雖然他不太善常社交。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그분이 지금처럼 사분오열된 그룹을 조율할 수 있을 거라는 기대는 안 드는군요.","JPN":"あの方が今の分裂したグループをうまくまとめられるとは思えませんね。","ENG":"I do not expect him to be able to lead the Group in its divided state right now.","TWN":"我不認為他有能力，可以將四分五裂的集團重新整合起來。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"메카닉스 대표가 부회장님 다음으로 살해된 게…… 단순히 우연일까?","JPN":"メカニックス代表が副会長の次に殺害されたのは……ただの偶然？","ENG":"So, is it just a coincidence that the CEO of Mechanics got killed right after the Vice Chairman?","TWN":"機械代表在副會長之後遭到殺害……只是巧合嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"……아무튼 일이 이 지경인데 감찰과는 대체 뭘 하고 있는 건가?","JPN":"……とにかくこんな状況なのに、監察課はいったい何をしているんだ？","ENG":"Why isn’t Investigations doing anything about this?","TWN":"……事情都已經變成這樣，監察科到底是幹什麼吃的！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"감찰과장! 사건 담당 감찰관은 어디 있나!","JPN":"監察課長！　事件担当の監察官はどこにいるんだ！","ENG":"Chief Inspector! Who’s leading this case?!","TWN":"監察科長！把負責這次事件的監察官給我找來！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"두구두구두구~","JPN":"ドゴドゴドゴドゴ……","ENG":"Drumroll please...!","TWN":"噜嘟嘟噜嘟噜～"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L47_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"짜잔!!","JPN":"ババン！！","ENG":"Kachow!","TWN":"鏘鏘！！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그대들의 부름에 응하여 파사의 추적자, 나 라파엘라 주리 더 에빌 체이서가 등장!","JPN":"お前たちの呼びかけに応じ、破邪の追跡者、ラファエラ・ジュリー・ザ・エビルチェイサー参上！","ENG":"I heed your call. Here comes the Chaser of Evil, Raphaela Juri the Evil Chaser!","TWN":"你們要找的人就是我，破邪追擊者 拉菲樂·朱莉·除惡者登場！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"이 중요한 사건을 저런 꼬맹이에게 맡기고 있었다고?!","JPN":"この大事な事件をあんなガキに任せていたのか！？","ENG":"Wait a minute. The lead on this case is a little KID?!","TWN":"這麼重要的事，你們竟然交給這個小鬼負責？！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"감찰과장! 자네 지금 제정신이야?","JPN":"監察課長！　君は正気か？","ENG":"Chief Inspector! Are you out of your mind?!","TWN":"監察科長！你腦袋裝大便嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHIEF_NPC_ALPHA_NULL","text":{"KOREA":"죄, 죄송합니다! 조금 괴짜 같긴 하지만 실력은……!","JPN":"す、すみません！　少し変わったところはありますが、実力だけは……！","ENG":"A-apologies! She may be a little quirky, but the skills are...!","TWN":"抱…抱歉！雖然她有點奇怪，但能力……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"지금 어디서 변명이야! 인성이 깡통인데 실력은 얼어죽을!","JPN":"言い訳するな！　あんなふざけたガキに実力も何も……！","ENG":"Are you kidding me?! Just look at her! You think I care about her \\"skills\\"?!","TWN":"你還敢給我頂嘴！你這個成事不足敗事有餘的傢伙！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"크흠, 꽤 바쁜 용무신가 본데 누구 전화요?","JPN":"ゴホン、ずいぶんと忙しいようだが、誰からの電話かね？","ENG":"Ahem. You seem preoccupied. Who’s calling?","TWN":"咳咳，我看你好像很忙嘛，是誰打來的？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"에헤헷. 미안. 사건과 관련된 중요한 제보라…….","JPN":"えへへ、ごめん。事件に関する重要な情報で……","ENG":"Ahaha... Sorry, but it’s an important call about the case...","TWN":"嘿嘿嘿，不好意思喔，是跟事件有關的……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"여보세요? 아, 네! 파사의 목소리님! 잠시만요!","JPN":"もしもし？　あ、はい！　破邪の声様！　少しお待ちください！","ENG":"Hello? Uh-huh! Mr. Voice of Evil Eradication! Hold on a sec!","TWN":"喂？喔，是！破邪之聲！請稍候！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……뭐 S급 카운터라도 되는 건가?","JPN":"……意外とS級カウンターだとか？","ENG":"Is she a Grade S Counter or something?","TWN":"……她真的是S級制裁者嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"후우……. 회장님이 떠나신 뒤로 하나같이 엉망이로군.","JPN":"ふう……会長が亡くなってから、何もかもめちゃくちゃだな。","ENG":"Ugh... Everything’s been a mess since our President passed away.","TWN":"哀哀……自從會長死後，公司就變成這樣亂七八糟的！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"방금 담당 감찰관의 경박한 언행을 보고 다들 느끼시는 바가 많을 것으로 생각됩니다.","JPN":"先ほどの担当監察官の軽薄な言動を見て、\\n皆様も感じるところが多いと思われます。","ENG":"I’m sure everyone feels concerned as I do after witnessing the childish remarks of the lead investigator.","TWN":"剛剛看到負責的監察官言行如此輕率後，相信大家應該都很有感。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"사건을 쉬쉬하기도 더는 힘들어졌으니, 도시관리국과 공개수사를 하는 게 어떻겠습니까?","JPN":"これ以上事件をもみ消すのも難しくなってきましたし、\\n都市管理局に連絡して公開捜査に踏み切るのはいかがでしょう？","ENG":"The case has gotten out of control. I suggest that we turn it into an open investigation in cooperation with City Managements. Any objections?","TWN":"既然消息已經壓不住，那不如和城市管理局合作，公開調查吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"이렇게 믿음직한 수사관 분들도 모셨으니 말입니다.","JPN":"このように頼もしい捜査官の方もお招きしましたので。","ENG":"I’ve taken the liberty to invite the most trustworthy officers for the job.","TWN":"歡迎值得信賴的人民保母們！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하……. 안녕하세요. 이렇게 부담스러운 자리는 오랜만이네요.","JPN":"あはは……こんにちは。ここまでプレッシャーを感じる現場は久しぶりですね。","ENG":"Ahaha... Hello. It’s been a while since I felt this nervous.","TWN":"哈哈哈……大家好，好久沒有出席這麼沉重的場合。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"특수능력 범죄 대응 전담반 제4 특별기동수사대, 경위 강소영이라고 합니다.","JPN":"特殊能力犯罪担当班、第4特別機動捜査隊警部補、マエカワ・ナツミと申します。","ENG":"I am Lieutenant Kang Soyoung of SWAT 4, Counter-superpowered crimes team.","TWN":"特殊能力犯罪應對專案小組 第四特遣機動隊，我是姜素英警衛。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……이유미 경정입니다. 카운터 관련 범죄라는 소식을 듣고 왔어요.","JPN":"……警視のカスカベ・ユミです。カウンター関連の犯罪と聞いて参りました。","ENG":"...I am Major Lee Yumi. I came to help on your Counter-related case.","TWN":"……我是李悠美警政，我聽說這裡有發生制裁者犯罪事件。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DIRECTORB_NPC_ALPHA_NULL","text":{"KOREA":"두 분은 경찰 기관 소속이지만 리플레이서 사태 때 큰 공로를 세워서…….","JPN":"お二人は警察機関の所属ではありますが、リプレイサー事件の際に大きな貢献を……","ENG":"Both are police officers, but they played a significant role in the Replacer incident...","TWN":"這兩位雖然是隸屬於警察機關，但在克隆事件時可是立下大功……"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_POLICE_SWAT_4","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"아, 알아냈어!! 내가 알아냈다구!!","JPN":"き、聞いて！！　私が突き止めたんだよ！！","ENG":"I got it!! I figured it out!!","TWN":"知道了！！我知道了！！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CAR_SKID"},{"id":"L29_1","type":"dialog","speaker":"DIRECTORA_NPC_ALPHA_NULL","text":{"KOREA":"감찰과장! 저 꼬맹이 당장 끌고 안 나가나!","JPN":"監察課長！　あのガキを今すぐここから連れ出せ！","ENG":"Inspector! Get that kid out of here!","TWN":"監察科長！還不快把那小鬼給我拖出去！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"실랑이 할 시간 없어! 늦기 전에 어서 가야 돼!","JPN":"ごたごたしてる場合じゃない！　手遅れになる前に早く行かないと！","ENG":"We don’t have time! We need go before it’s too late!","TWN":"沒時間跟你們解釋！我得趕緊出發！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"범인의 다음 표적에게!","JPN":"犯人の次のターゲットがいるところに！","ENG":"To their next target!","TWN":"去找犯人的下一個目標！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"야, 넌 폼이란 폼은 다 잡아 놓고 거기서 지면 어떡하냐.","JPN":"ねえ、散々カッコつけておいて、あそこで負けたらどうするのよ。","ENG":"Hey, how could you lose after bolstering like that, huh?","TWN":"喂，你姿勢擺得一副很厲害的樣子，結果竟然打輸？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"더블 카운터 선언한 내가 다 부끄럽잖아.","JPN":"ダブルカウンターを宣言した私まで恥ずかしいじゃない。","ENG":"Now I’m embarrassed to have declared Double Counter.","TWN":"虧我還信誓旦旦地說我們是制裁者二人組，很丟臉欸！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"훗. 소녀를 적들의 마수에서 지키기 위해 자세를 풀지 않았다면 승리는 내 것이었다.","JPN":"フッ。少女を敵の魔の手から守るために姿勢を崩さなかったなら、勝利は私のものだった。","ENG":"Pfft. If I hadn’t tried to protect you from those beasts, victory would’ve been mine, girl.","TWN":"哼，要不是因為要拯救少女脫離敵人的魔掌，害我的姿勢沒擺好，否則我怎麼會輸？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"뭐야? 그래서 내 탓이라고?","JPN":"なに？　つまり私のせいってこと？","ENG":"What?! So it’s my fault we lost?!","TWN":"你說什麼？怪我囉？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"파사의 심판자가 아니라 파사의 변명꾼이었어, 너?","JPN":"破邪の審判者じゃなくて、破邪の言い訳屋だったってわけ？","ENG":"Judicator of Evil? More like Blamer of Evil.","TWN":"我看你不要叫什麼破邪審判者，改名叫破邪理由伯吧！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"용납할 수 없는 망발이군! 해보자는 건가, 정의의 사자 지망생!","JPN":"容認できない妄言だな！　勝負を挑むつもりか？　正義の味方の卵よ！","ENG":"How dare you! Are you challenging me, servant of justice?!","TWN":"令人無法原諒的發言！是想較量一下嗎？想成為正義使者的少女！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"둘 다 꼴값 좀 그만 떨어. 아까부터 내 시신경이 몸둘 바를 모르고 있어.","JPN":"二人ともいい加減にしなさい。\\nさっきからずっと、私の視神経がイライラしているんです。","ENG":"Will you two just stop? I can’t even look at you two anymore.","TWN":"你們兩個都別再丟人了吧？我都替你們感到不好意思了。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"우리 사이가 별 사이 아니긴 하지만, 에티켓은 지켜 줘.","JPN":"別に私たちは仲がいいわけではありませんが、エチケットくらい守ってください。","ENG":"Even though we’re not that close, how about having some manners?","TWN":"雖然我跟你們沒什麼關係，但是面子還是顧一下吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"응? 초원이 넌 또 뭐 하는 거야?","JPN":"うん？　ナオちゃんは何をしているの？","ENG":"Huh? What are you doing here, Chowon?","TWN":"嗯？初源，你又在幹嘛？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"작전 중이던 용병이 적의 수용소에 감금되는 건 흔한 일이야.","JPN":"作戦中の傭兵が敵の収容所に監禁されるのはよくあることです。","ENG":"Mercenaries getting caught by the enemy is something that happens on a daily basis.","TWN":"傭兵在作戰時，被監禁在敵人的集中營是常有的事。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"그리고 그런 상황에 대비해 안경다리로 자물쇠를 여는 방법도 존재하지.","JPN":"そして、そのような状況に備えてメガネのテンプルで錠を開ける方法があります。","ENG":"We also happen to know how to open locks with the temple tip of our glasses.","TWN":"為了應付這種情況，學會用眼鏡腳套開鎖是必須的。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"여, 열렸다! 진짜 열렸어!","JPN":"あ、開いた！　本当に開いたよ！","ENG":"I-it's open! She really unlocked it!","TWN":"哇，開咧？好厲害！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"훌륭하군. 그 손재주라면 파사의 성소를 가로막은 봉인도 문제 없겠어.","JPN":"素晴らしい。その器用さなら、破邪の聖所を塞いでいる封印すら問題にならないだろう。","ENG":"Excellent. With those skills, you won’t have an issue unsealing the Sanctuary of Evil Eradication.","TWN":"真是出色！憑你的技巧，要解開破邪聖所的封印也不是問題吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"유익하지 않은 감탄사 고마워.","JPN":"嬉しくならない褒め言葉をありがとう。","ENG":"Thanks, but no thanks.","TWN":"謝謝你們完全幫不上忙的讚美。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"자. 일어나. 움직이자.","JPN":"さあ、立ち上がってください。行きましょう。","ENG":"Okay. Get up. We’re moving.","TWN":"起來吧，要走了！"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"응? 움직이다니…… 어디로?","JPN":"え？　行くって……どこへ？","ENG":"Huh? To where?","TWN":"嗯？走……要走去哪裡？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"헤어지기 전에 예비로 가지고 다니던 안경을 리더에게 줬어.","JPN":"別れる前に予備用のメガネをリーダーに渡しました。","ENG":"Before Leader and I split, I gave her my back-up glasses.","TWN":"和老大分開前，以防萬一我有把我的眼鏡借給她。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"내가 쓴 것과 연동이 된 상태라 실시간으로 위치 추적이 가능해.","JPN":"私がかけているモノと連動しているので、リアルタイムで位置追跡が可能です。","ENG":"It’s synced with the one I’m wearing now, and I can track her location with it.","TWN":"那副眼鏡和我用的是互連的，所以可以即時掌握老大的位置。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"……이미 안경이 본체 아닌가?","JPN":"……もはや眼鏡が本体ではないか？","ENG":"Your glasses seem more useful than you, no?","TWN":"……眼鏡根本就是她的代名詞吧？"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그러게……. 부정할 수가 없어.","JPN":"だよね……否定できない。","ENG":"Well, I can’t argue with that.","TWN":"對啊……非常認同。"},"stage":{"bg":"PRISON_NIGHT","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"}}}}]`);export{e as default};